    TELEGRAM_BOT_TOKEN_set: Boolean(cfg.TELEGRAM_BOT_TOKEN),
    MONGODB_URI_set: Boolean(cfg.MONGODB_URI),
    ADMIN_TELEGRAM_ID_set: Boolean(process.env.ADMIN_TELEGRAM_ID),
