import { log, safeErr } from "../lib/logger.js";

const DEX_BASE = "https://api.dexscreener.com";
const SUPPORTED = new Map([
  ["ethereum", { id: "ethereum", name: "Ethereum", chainId: 1 }],
  ["bsc", { id: "bsc", name: "BNB Smart Chain", chainId: 56 }],
]);

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function fetchJson(url, meta = {}) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 15000);

  log.info("external api call start", { service: "DexScreener", ...meta });

  try {
    const res = await fetch(url, {
      headers: { accept: "application/json" },
      signal: controller.signal,
    });
    const text = await res.text();
    const json = text ? JSON.parse(text) : null;

    if (!res.ok) {
      throw new Error(`HTTP ${res.status}`);
    }

    log.info("external api call success", { service: "DexScreener", ...meta });
    return json;
  } catch (err) {
    log.warn("external api call failed", {
      service: "DexScreener",
      ...meta,
      err: safeErr(err),
    });
    throw err;
  } finally {
    clearTimeout(timeout);
  }
}

function marketCapOf(pair) {
  const mc = Number(pair?.marketCap);
  if (Number.isFinite(mc) && mc > 0) return mc;

  const fdv = Number(pair?.fdv);
  if (Number.isFinite(fdv) && fdv > 0) return fdv;

  return null;
}

function pairAgeMs(pair) {
  const createdAt = Number(pair?.pairCreatedAt || 0);
  if (!Number.isFinite(createdAt) || createdAt <= 0) return Number.MAX_SAFE_INTEGER;
  return Date.now() - createdAt;
}

function normalizePair(pair) {
  const chain = SUPPORTED.get(String(pair?.chainId || "").toLowerCase());
  if (!chain) return null;

  const tokenAddress = String(pair?.baseToken?.address || "").toLowerCase();
  if (!tokenAddress) return null;

  const marketCap = marketCapOf(pair);

  return {
    chain: chain.id,
    chainName: chain.name,
    chainId: chain.chainId,
    tokenAddress,
    pairAddress: String(pair?.pairAddress || "").toLowerCase(),
    name: String(pair?.baseToken?.name || "Unknown"),
    symbol: String(pair?.baseToken?.symbol || "UNKNOWN"),
    marketCap,
    liquidity: Number(pair?.liquidity?.usd || 0) || null,
    dexId: String(pair?.dexId || ""),
    url: String(pair?.url || ""),
    firstSeenAt: pair?.pairCreatedAt ? new Date(Number(pair.pairCreatedAt)) : new Date(),
  };
}

export async function discoverRecentPairs() {
  const candidates = [];

  try {
    const profiles = await fetchJson(`${DEX_BASE}/token-profiles/latest/v1`, {
      feature: "latest-token-profiles",
    });

    const rows = Array.isArray(profiles) ? profiles : [];
    const supportedProfiles = rows
      .filter((p) => SUPPORTED.has(String(p?.chainId || "").toLowerCase()))
      .slice(0, 40);

    for (const profile of supportedProfiles) {
      const chainId = String(profile.chainId || "").toLowerCase();
      const tokenAddress = String(profile.tokenAddress || "").toLowerCase();
      if (!chainId || !tokenAddress) continue;

      try {
        await sleep(150);
        const data = await fetchJson(
          `${DEX_BASE}/latest/dex/tokens/${encodeURIComponent(tokenAddress)}`,
          { feature: "token-pairs", chain: chainId }
        );

        const bestPair = (Array.isArray(data?.pairs) ? data.pairs : [])
          .filter((p) => String(p?.chainId || "").toLowerCase() === chainId)
          .sort((a, b) => pairAgeMs(a) - pairAgeMs(b))[0];

        const candidate = normalizePair(bestPair);
        if (candidate) candidates.push(candidate);
      } catch {
        continue;
      }
    }
  } catch {
    return [];
  }

  const seen = new Set();
  return candidates.filter((candidate) => {
    const key = `${candidate.chain}:${candidate.tokenAddress}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

scanner.js.content:
import { cfg } from "../lib/config.js";
import {
  countAlerts,
  getScannerState,
  saveAlertIfNew,
  updateScannerState,
} from "../lib/db.js";
import { log, safeErr } from "../lib/logger.js";
import { sendAlert } from "./alerts.js";
import { discoverRecentPairs } from "./marketData.js";
import { verifyTokenSecurity } from "./tokenSecurity.js";

const MARKET_CAP_LIMIT = 2000;

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

export function createScanner({ bot }) {
  let running = false;
  let cycleRunning = false;
  let stopped = false;
  let startedAt = null;
  let lastScanAt = null;
  let lastError = "";
  let lastMemoryLogAt = 0;

  async function cycle(reason = "scheduled") {
    if (cycleRunning) {
      log.warn("scanner cycle skipped", { reason, skippedReason: "already-running" });
      return { candidatesChecked: 0, alertsSent: 0, skipped: true };
    }

    cycleRunning = true;
    const started = Date.now();
    let candidatesChecked = 0;
    let alertsSent = 0;

    log.info("scanner cycle start", { reason });

    try {
      const candidates = await discoverRecentPairs();

      for (const candidate of candidates) {
        candidatesChecked += 1;

        if (candidate.marketCap === null || candidate.marketCap >= MARKET_CAP_LIMIT) {
          continue;
        }

        let security;
        try {
          security = await verifyTokenSecurity(candidate);
        } catch (err) {
          lastError = safeErr(err);
          continue;
        }

        if (!security.ok) continue;

        const isNew = await saveAlertIfNew({
          chain: candidate.chain,
          tokenAddress: candidate.tokenAddress,
          pairAddress: candidate.pairAddress,
          symbol: candidate.symbol,
          name: candidate.name,
          marketCap: candidate.marketCap,
          liquidity: candidate.liquidity,
          sourceUrls: {
            dex: candidate.url,
            security: "https://gopluslabs.io/",
          },
          firstSeenAt: candidate.firstSeenAt,
          renouncedStatus: security.renounced.status,
          liquidityLockStatus: security.liquidityLock.status,
          lockedPercent: security.liquidityLock.lockedPercent,
        });

        if (!isNew) continue;

        const sent = await sendAlert(bot, candidate, security);
        if (sent) alertsSent += 1;
      }

      lastScanAt = new Date();
      lastError = "";
      await updateScannerState({
        running,
        lastScanAt,
        lastError,
        lastCandidatesChecked: candidatesChecked,
        lastAlertsSent: alertsSent,
      });

      log.info("scanner cycle finish", {
        reason,
        candidatesChecked,
        alertsSent,
        ms: Date.now() - started,
      });

      return { candidatesChecked, alertsSent, skipped: false };
    } catch (err) {
      lastError = safeErr(err);
      await updateScannerState({ running, lastError });
      log.error("scanner cycle failed", {
        reason,
        candidatesChecked,
        alertsSent,
        err: lastError,
      });
      return { candidatesChecked, alertsSent, skipped: false, error: lastError };
    } finally {
      cycleRunning = false;
    }
  }

  async function loop() {
    running = true;
    startedAt = new Date();
    await updateScannerState({ running, startedAt, scanIntervalMs: cfg.SCAN_INTERVAL_MS });
    log.info("scanner polling started", { scanIntervalMs: cfg.SCAN_INTERVAL_MS });

    while (!stopped) {
      await cycle("scheduled");

      const now = Date.now();
      if (now - lastMemoryLogAt > 60000) {
        const m = process.memoryUsage();
        log.info("memory", {
          rssMB: Math.round(m.rss / 1e6),
          heapUsedMB: Math.round(m.heapUsed / 1e6),
        });
        lastMemoryLogAt = now;
      }

      await sleep(cfg.SCAN_INTERVAL_MS);
    }

    running = false;
    await updateScannerState({ running });
  }

  return {
    start() {
      if (running) return;
      stopped = false;
      loop().catch((err) => {
        lastError = safeErr(err);
        log.error("scanner loop failed", { err: lastError });
      });
    },

    stop() {
      stopped = true;
    },

    scanNow() {
      return cycle("manual");
    },

    async getStatus() {
      const saved = await getScannerState();
      return {
        running,
        cycleRunning,
        startedAt,
        lastScanAt: lastScanAt || saved?.lastScanAt || null,
        scanIntervalMs: cfg.SCAN_INTERVAL_MS,
        totalAlerts: await countAlerts(),
        lastError: lastError || saved?.lastError || "",
      };
